function timerManager() {}

let _nextId = 1;
const _timers = new Map();

timerManager.mySetTimeout = function mySetTimeout(fn, delay) {
  const id = _nextId++;
  const handle = setTimeout(() => {
    _timers.delete(id);
    fn();
  }, delay);
  _timers.set(id, handle);
  return id;
};

timerManager.myClearTimeout = function myClearTimeout(id) {
  const handle = _timers.get(id);
  if (handle != null) {
    clearTimeout(handle);
    _timers.delete(id);
  }
};

timerManager.myClearAllTimeouts = function myClearAllTimeouts() {
  for (const handle of _timers.values()) {
    clearTimeout(handle);
  }
  _timers.clear();
};

export default timerManager;
